#include <string.h>

// Check if payload is an HTTP request WITHOUT Authorization header
// Returns 1 if request lacks auth, 0 otherwise
static inline int em_is_request_without_auth(const char *payload, int len) {
    if (payload == NULL || len < 10) return 0;

    // Must be an HTTP request (starts with method)
    if (strncmp(payload, "GET ", 4) != 0 &&
        strncmp(payload, "POST ", 5) != 0 &&
        strncmp(payload, "PUT ", 4) != 0 &&
        strncmp(payload, "DELETE ", 7) != 0 &&
        strncmp(payload, "PATCH ", 6) != 0) {
        return 0;  // Not a request
    }

    // Search for Authorization header
    const char *p = payload;
    const char *end = payload + len;

    while (p < end - 14) {
        if ((*p == 'A' || *p == 'a') &&
            strncasecmp(p, "Authorization:", 14) == 0) {
            return 0;  // Has auth - not an attack
        }
        p++;
    }

    return 1;  // Request without Authorization
}

// Check if payload is HTTP 401 response
static inline int em_is_401_response(const char *payload, int len) {
    if (payload == NULL || len < 12) return 0;

    // Check for "HTTP/1.x 401"
    if (strncmp(payload, "HTTP/1.", 7) != 0) return 0;

    const char *p = payload + 8;
    while (*p == ' ' && p < payload + len) p++;

    return (strncmp(p, "401", 3) == 0) ? 1 : 0;
}
